#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <chrono>

template<typename T>
void verify(const T* ref_out, const T* out, int64_t n)
{
  int error = 0;
  for (int64_t i = 0; i < n; i++) {
    if (ref_out[i] != out[i]) {
      error = 1;
      printf("@%zu: %lf != %lf\n", (size_t)i, (double)ref_out[i], (double)out[i]);
      break;
    }
  }
  printf("%s\n", error ? "FAIL" : "PASS");
}

#define LOG_MEM_BANKS 5
#define OFFSET(n) ((n) >> LOG_MEM_BANKS)

template<typename T, int N>
__global__ void scanKernelWithConflicts(T* in, T* out, int64_t num_blocks)
{
  int64_t bid = blockIdx.x;
  if (bid >= num_blocks) return;

  extern T temp_shared[N];
  T* temp = temp_shared;

  int thid = threadIdx.x;
  int num_threads = N / 2;

  T* t_in  = in + bid * N;
  T* t_out = out + bid * N;

  if (thid < num_threads) {
    temp[2*thid]   = t_in[2*thid];
    temp[2*thid+1] = t_in[2*thid+1];
  }

  int offset = 1;
  for (int d = N >> 1; 0 < d; d >>= 1)
  {
    __syncthreads();
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      temp[bi] += temp[ai];
    }
    offset *= 2;
  }

  if (thid == 0) temp[N-1] = 0; 
  for (int d = 1; N > d; d *= 2) 
  {
    offset = offset >> (1);
    __syncthreads();
    if (d > thid)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      T t = temp[ai];
      temp[ai] = temp[bi];
      temp[bi] += t;
    }
  }

  if (thid < num_threads) {
    t_out[2*thid] = temp[2*thid];
    t_out[2*thid+1] = temp[2*thid+1];
  }
}

// Explicit specialization for template kernel with shared memory
template<typename T, int N>
__global__ void scanKernelWithConflictsImpl(T* in, T* out, int64_t num_blocks)
{
  int64_t bid = blockIdx.x;
  if (bid >= num_blocks) return;

  __shared__ T temp[N];
  T* temp_ptr = temp;

  int thid = threadIdx.x;
  int num_threads = N / 2;

  T* t_in  = in + bid * N;
  T* t_out = out + bid * N;

  if (thid < num_threads) {
    temp_ptr[2*thid]   = t_in[2*thid];
    temp_ptr[2*thid+1] = t_in[2*thid+1];
  }

  int offset = 1;
  for (int d = N >> 1; 0 < d; d >>= 1)
  {
    __syncthreads();
    if (thid < d)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      temp_ptr[bi] += temp_ptr[ai];
    }
    offset *= 2;
  }

  if (thid == 0) temp_ptr[N-1] = 0; 
  for (int d = 1; N > d; d *= 2) 
  {
    offset = offset >> (1);
    __syncthreads();
    if (d > thid)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      T t = temp_ptr[ai];
      temp_ptr[ai] = temp_ptr[bi];
      temp_ptr[bi] += t;
    }
  }

  if (thid < num_threads) {
    t_out[2*thid] = temp_ptr[2*thid];
    t_out[2*thid+1] = temp_ptr[2*thid+1];
  }
}

template<typename T, int N>
__global__ void scanKernelNoConflicts(T* in, T* out, int64_t num_blocks)
{
  int64_t bid = blockIdx.x;
  if (bid >= num_blocks) return;

  __shared__ T temp[2*N];
  T* temp_ptr = temp;

  int thid = threadIdx.x;
  int num_threads = N / 2;

  T* t_in  = in + bid * N;
  T* t_out = out + bid * N;

  if (thid < num_threads) {
    int a = thid;
    int b = a + (N/2);
    int oa = OFFSET(a);
    int ob = OFFSET(b);

    temp_ptr[a + oa] = t_in[a];
    temp_ptr[b + ob] = t_in[b];
  }

  int offset = 1;
  for (int d = N >> 1; 0 < d; d >>= 1)
  {
    __syncthreads();
    if (d > thid)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      ai += OFFSET(ai);
      bi = bi + OFFSET(bi);
      temp_ptr[bi] += temp_ptr[ai];
    }
    offset *= 2;
  }

  if (0 == thid) temp_ptr[N-1+OFFSET(N-1)] = 0; 
  for (int d = 1; N > d; d *= 2) 
  {
    offset = offset >> (1);
    __syncthreads();
    if (d > thid)
    {
      int ai = offset*(2*thid+1)-1;
      int bi = offset*(2*thid+2)-1;
      ai = ai + OFFSET(ai);
      bi = bi + OFFSET(bi);
      T t = temp_ptr[ai];
      temp_ptr[ai] = temp_ptr[bi];
      temp_ptr[bi] += t;
    }
  }
  __syncthreads(); 

  if (thid < num_threads) {
    int a = thid;
    int b = a + (N/2);
    int oa = OFFSET(a);
    int ob = OFFSET(b);
    t_out[a] = temp_ptr[a + oa];
    t_out[b] = temp_ptr[b + ob];
  }
}

template<typename T, int N>
void runTest (const int64_t n, const int repeat, bool timing = false)
{
  int64_t num_blocks = (n + N - 1) / N;
  int64_t nelems = num_blocks * N; 
  int64_t bytes = nelems * sizeof(T);

  T *in = (T*) malloc (bytes);
  T *out = (T*) malloc (bytes);
  T *ref_out = (T*) malloc (bytes);

  srand(123);
  for (int64_t idx = 0; idx < nelems; idx++) in[idx] = rand() % 5 + 1;

  // Reference calculation on CPU
  T *t_in = in;
  T *t_out = ref_out;
  for (int64_t blk = 0; blk < num_blocks; blk++) {
    t_out[0] = 0;
    for (int i = 1; i < N; i++)
      t_out[i] = t_out[i-1] + t_in[i-1];
    t_out += N;
    t_in += N;
  }

  T *d_in, *d_out;
  cudaMalloc(&d_in, bytes);
  cudaMalloc(&d_out, bytes);
  cudaMemcpy(d_in, in, bytes, cudaMemcpyHostToDevice);

  int threads_per_block = N / 2;

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; i < repeat; i++) {
    scanKernelWithConflictsImpl<T, N><<<(int)num_blocks, threads_per_block>>>(d_in, d_out, num_blocks);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();

  cudaMemcpy(out, d_out, bytes, cudaMemcpyDeviceToHost);

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/  bank conflicts): %f (us)\n",
           sizeof(T), (time * 1e-3f) / repeat);
  }
  if (!timing) verify(ref_out, out, nelems);

  start = std::chrono::steady_clock::now();
  for (int i = 0; i < repeat; i++) {
    scanKernelNoConflicts<T, N><<<(int)num_blocks, threads_per_block>>>(d_in, d_out, num_blocks);
  }

  end = std::chrono::steady_clock::now();
  auto bcao_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();

  cudaMemcpy(out, d_out, bytes, cudaMemcpyDeviceToHost);

  if (timing) {
    printf("Element size in bytes is %zu. Average execution time of scan (w/o bank conflicts): %f (us). ",
           sizeof(T), (bcao_time * 1e-3f) / repeat);
    printf("Reduce the time by %.1f%%\n", (time - bcao_time) * 1.0 / time * 100);
  }

  if (!timing) verify(ref_out, out, nelems);

  cudaFree(d_in);
  cudaFree(d_out);
  free(in);
  free(out);
  free(ref_out);
}

template<int N>
void run (const int n, const int repeat) {
  for (int i = 0; 2 > i; i++) {
    bool report_timing = 0 < i;
    printf("\nThe number of elements to scan in a thread block: %d\n", N);
    runTest< char, N>(n, repeat, report_timing);
    runTest<short, N>(n, repeat, report_timing);
    runTest<  int, N>(n, repeat, report_timing);
    runTest< long, N>(n, repeat, report_timing);
  }
}

int main(int argc, char* argv[])
{
  if (argc != 3) {
    printf("Usage: %s <number of elements> <repeat>\n", argv[0]);
    return 1;
  }
  const int n = atoi(argv[1]);
  const int repeat = atoi(argv[2]);

  run< 128>(n, repeat);
  run< 256>(n, repeat);
  run< 512>(n, repeat);
  run<1024>(n, repeat);
  run<2048>(n, repeat);

  return 0;
}
